#include "rsbench.cuh"
#include <cuda_runtime.h>

int g_platform_id = -1;
int g_device_id = -1;
extern double g_last_sim_runtime;

static int validate_and_print_results_opencl(Input input, double runtime, unsigned long vhash, double sim_runtime);

int main(int argc, char * argv[])
{
	int version = 13;
	double start, stop;

	Input input = read_CLI(argc, argv);

	logo(version);
	center_print("INPUT SUMMARY", 79);
	border_print();
	print_input_summary(input);

	border_print();
	center_print("INITIALIZATION", 79);
	border_print();

	start = get_time();

	SimulationData SD = initialize_simulation(input);

	stop = get_time();

	printf("Initialization Complete. (%.2lf seconds)\n", stop-start);

	unsigned long vhash = 0;

	start = get_time();
	double sim_runtime = 0.0;

	if( input.simulation_method == EVENT_BASED )
	{
		if( 0 == input.kernel_id )
		{
			run_event_based_simulation(input, SD, &vhash);
			sim_runtime = g_last_sim_runtime;
		}
		else
		{
			printf("Error: No kernel ID %d found!\n", input.kernel_id);
			exit(1);
		}
	}
	else if( input.simulation_method == HISTORY_BASED )
	{
		printf("History-based simulation not implemented in OpenMP offload code. Instead,\nuse the event-based method with \"-m event\" argument.\n");
		exit(1);
	}

	stop = get_time();

	vhash %= 999983;

	printf("Simulation Complete.\n");

	border_print();
	center_print("RESULTS", 79);
	border_print();

	int is_invalid = validate_and_print_results_opencl(input, stop-start, vhash, sim_runtime);

	border_print();

	return is_invalid;
}

